#include<bits/stdc++.h>
using namespace std;
const int N=1005;
int n,a,b,w[N],dp[N][N],ans;
int main()
{
    cin>>n>>a>>b;
    for(int i=1;i<=n;i++) cin>>w[i];
    for(int i=1;i<=n;i++)
    {
        for(int a1=a;a1>=0;a1--)
        {
            for(int b1=b;b1>=0;b1--)
            {
                if(b1>=w[i]) dp[a1][b1]=max(dp[a1][b1],dp[a1][b1-w[i]]+w[i]);
                if(a1>=w[i]) dp[a1][b1]=max(dp[a1][b1],dp[a1-w[i]][b1]+w[i]);
                ans=max(ans,dp[a1][b1]);
            }
        }
    }
    cout<<ans;
    return 0;
}
